mapper.select:
SELECT *
FROM certificate
WHERE student_id = #{studentId}

    AND status = #{status}


    AND course_id = #{courseId}


    AND (
        certificate_name LIKE CONCAT('%', #{keyword}, '%')
        OR certificate_number LIKE CONCAT('%', #{keyword}, '%')
    )

ORDER BY issuing_date DESC, created_time DESC

SELECT COUNT(1)
FROM certificate
WHERE student_id = #{studentId}
  AND course_id = #{courseId}
  AND status = #{status}

SELECT *
FROM certificate
WHERE teacher_id = #{teacherId}

    AND course_id = #{courseId}


    AND status = #{status}

ORDER BY issuing_date DESC, created_time DESC

SELECT COUNT(1)
FROM certificate
WHERE certificate_number = #{certificateNumber}

SELECT *
FROM certificate
WHERE student_id = #{studentId}

    AND status = #{status}

ORDER BY issuing_date DESC, created_time DESC

mapper.update:
UPDATE certificate
SET verification_count = IFNULL(verification_count, 0) + 1,
    last_verification_time = #{lastVerificationTime},
    updated_time = #{updatedTime}
WHERE id = #{certificateId}
